-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "فقه الأسرة" (fiqh-usrah) — تستنفد العنقود بالكامل
-- (9 تصنيفات فرعية من أصل 9، كلها بلا محتوى): الخطبة والزواج، عقد
-- النكاح، حقوق الزوجين، الطلاق والخلع، الحضانة والنسب، الرضاع، الظهار
-- واللعان، العدة، النفقات.
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: فقه السنة للسيد
-- سابق، الفقه الإسلامي وأدلته للزحيلي، المغني لابن قدامة، الأحوال
-- الشخصية لأبي زهرة، بداية المجتهد لابن رشد.
-- كل آية استُشهد بها (الروم:21، النساء:4، النساء:19، البقرة:229،
-- الأحزاب:5، البقرة:233، المجادلة:2، البقرة:228، الطلاق:7) تحقَّقت
-- حرفياً من artifacts/majalis/public/data/quran محلياً عبر حقل
-- numberInSurah قبل الإدراج.
-- كل حديث مستشهَد به (9 أحاديث) متحقَّق حرفياً عبر WebSearch قبل
-- الإدراج: «يا معشر الشباب من استطاع منكم الباءة فليتزوج» (متفق عليه،
-- البخاري 5065، ابن مسعود)، «لا نكاح إلا بولي» (أحمد والأربعة،
-- صححه ابن المديني والترمذي وابن حبان، أبو موسى الأشعري)، «خيركم
-- خيركم لأهله وأنا خيركم لأهلي» (الترمذي، صححه الألباني، عائشة)،
-- قصة خلع امرأة ثابت بن قيس «اقبل الحديقة وطلقها تطليقة» (البخاري، ابن
-- عباس)، «أنت أحق به ما لم تنكحي» (أبو داود وأحمد، حسنه الألباني
-- وشعيب الأرناؤوط، عبدالله بن عمرو)، «يحرم من الرضاعة ما يحرم من
-- الولادة» (متفق عليه، عائشة)، قصة لعان هلال بن أمية «البينة وإلا حد
-- في ظهرك» (البخاري، ابن عباس)، «انتقلي إلى بيت ابن عمك عمرو بن أم
-- مكتوم فاعتدي عنده» (مسلم، فاطمة بنت قيس)، «خذي ما يكفيك وولدك
-- بالمعروف» (متفق عليه، البخاري 5364 ومسلم 1714، عائشة عن هند بنت
-- عتبة).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات التسعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الخطبة والزواج
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e1eeb5d5-3331-48bf-9db7-dc91852a2423' AND title='مقاصد الزواج في الإسلام واستحباب النكاح لمن استطاع') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مقاصد الزواج في الإسلام واستحباب النكاح لمن استطاع', 'معنى النكاح شرعاً ومقاصده في السكن والمودة، وحث النبي صلى الله عليه وسلم الشباب القادرين على المبادرة إليه', 'e1eeb5d5-3331-48bf-9db7-dc91852a2423', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه ومقاصده', 'النكاح في اصطلاح الفقهاء: عقد يفيد حِلّ استمتاع كل من الزوجين بالآخر على الوجه المشروع. ومن أعظم مقاصده: تحقيق السكن النفسي والمودة والرحمة بين الزوجين، وإحصان الفرج وغض البصر، وحفظ النوع الإنساني بالتناسل، ولهذا رغّب الشرع فيه ترغيباً بالغاً لمن قدر عليه.', 1),
    (v_lesson, 'evidence', 'أصله القرآني وحث النبي عليه', 'قال تعالى: ﴿وَمِنْ آيَاتِهِ أَنْ خَلَقَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَاجًا لِّتَسْكُنُوا إِلَيْهَا وَجَعَلَ بَيْنَكُم مَّوَدَّةً وَرَحْمَةً﴾ (الروم: 21)، وعن عبد الله بن مسعود رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «يَا مَعْشَرَ الشَّبَابِ، مَنِ اسْتَطَاعَ مِنْكُمُ الْبَاءَةَ فَلْيَتَزَوَّجْ، فَإِنَّهُ أَغَضُّ لِلْبَصَرِ وَأَحْصَنُ لِلْفَرْجِ، وَمَنْ لَمْ يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ فَإِنَّهُ لَهُ وِجَاءٌ» متفق عليه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه السنة — السيد سابق (كتاب الزواج)', 1);
  END IF;

  -- 2) عقد النكاح
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='9821a5a2-bf91-435d-a14d-3648aaa9fb39' AND title='أركان عقد النكاح وشرط الولي فيه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أركان عقد النكاح وشرط الولي فيه', 'أركان عقد الزواج من إيجاب وقبول، ووجوب المهر حقاً للزوجة، واشتراط الولي عند جمهور الفقهاء لصحة العقد', '9821a5a2-bf91-435d-a14d-3648aaa9fb39', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أركانه وشروطه', 'ينعقد النكاح بإيجاب من الولي أو من في حكمه وقبول من الزوج بلفظ صريح يدل على الزواج. ومن شروط صحته عند جمهور الفقهاء: وجود الولي للمرأة، والإشهاد على العقد، وخلوّ الزوجين من الموانع الشرعية. والمهر حق خالص للزوجة تستحقه بالعقد، لا يجوز لأحد أخذه منها إلا برضاها.', 1),
    (v_lesson, 'evidence', 'أصل وجوب المهر واشتراط الولي', 'قال تعالى: ﴿وَآتُوا النِّسَاءَ صَدُقَاتِهِنَّ نِحْلَةً فَإِن طِبْنَ لَكُمْ عَن شَيْءٍ مِّنْهُ نَفْسًا فَكُلُوهُ هَنِيئًا مَّرِيئًا﴾ (النساء: 4)، وعن أبي موسى الأشعري رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «لَا نِكَاحَ إِلَّا بِوَلِيٍّ»، رواه أحمد وأبو داود والترمذي وابن ماجه والنسائي، وصححه علي بن المديني والترمذي وابن حبان.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'بداية المجتهد ونهاية المقتصد — القاضي أبو الوليد ابن رشد (كتاب النكاح)', 1);
  END IF;

  -- 3) حقوق الزوجين
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e941e162-5cfa-40fb-b96a-fb6637dc2e41' AND title='حقوق الزوجين المتبادلة وحسن العشرة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حقوق الزوجين المتبادلة وحسن العشرة', 'حق كل من الزوجين على الآخر بالمعروف، ومعيار النبي صلى الله عليه وسلم في قياس خيرية الرجل بحسن معاملته لأهله', 'e941e162-5cfa-40fb-b96a-fb6637dc2e41', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'حقوقهما المتبادلة', 'للزوجين حقوق متبادلة قائمة على المعروف: فللزوجة النفقة والمسكن وحسن العشرة، وللزوج الطاعة في المعروف والقيام على شؤون بيته، وقد جعل الشرع أساس العلاقة الزوجية المعاشرة بالمعروف لا مجرد أداء الواجبات، بحيث يراعي كل طرف حق الآخر ولو لم يكن ملزَماً به قضاءً.', 1),
    (v_lesson, 'evidence', 'أصل حسن العشرة ومعيار الخيرية', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا لَا يَحِلُّ لَكُمْ أَن تَرِثُوا النِّسَاءَ كَرْهًا... وَعَاشِرُوهُنَّ بِالْمَعْرُوفِ﴾ (النساء: 19)، وعن عائشة رضي الله عنها قالت: قال رسول الله صلى الله عليه وسلم: «خَيْرُكُمْ خَيْرُكُمْ لِأَهْلِهِ، وَأَنَا خَيْرُكُمْ لِأَهْلِي»، رواه الترمذي وصححه الألباني.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — الدكتور وهبة الزحيلي (كتاب الزواج)', 1);
  END IF;

  -- 4) الطلاق والخلع
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='da37330a-a21d-4b04-934c-e6f992f506c6' AND title='الطلاق الرجعي وأصل مشروعية الخلع') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الطلاق الرجعي وأصل مشروعية الخلع', 'تعريف الطلاق وأقسامه، ومشروعية الخلع كمخرج للزوجة حين تكره البقاء مع زوجها وتفتدي نفسها بمال', 'da37330a-a21d-4b04-934c-e6f992f506c6', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما وأقسامهما', 'الطلاق: حل رابطة الزواج بلفظ مخصوص، وينقسم إلى رجعي (يملك فيه الزوج ردّ زوجته أثناء العدة دون عقد جديد) وبائن. والخلع: فرقة بعوض تبذله الزوجة لزوجها لتفتدي به نفسها منه حين تكره البقاء معه وإن لم يكن منه تقصير، وهو فسخ عند جمهور الفقهاء لا طلاق رجعي.', 1),
    (v_lesson, 'evidence', 'أصل الطلاق الرجعي وأول خلع في الإسلام', 'قال تعالى: ﴿الطَّلَاقُ مَرَّتَانِ فَإِمْسَاكٌ بِمَعْرُوفٍ أَوْ تَسْرِيحٌ بِإِحْسَانٍ﴾ (البقرة: 229)، وعن ابن عباس رضي الله عنهما أن امرأة ثابت بن قيس أتت النبي صلى الله عليه وسلم فقالت: يا رسول الله، ثابت بن قيس ما أعيب عليه في خُلُق ولا دين، ولكني أكره الكفر في الإسلام، فقال رسول الله صلى الله عليه وسلم: «أَتَرُدِّينَ عَلَيْهِ حَدِيقَتَهُ؟» قالت: نعم، قال: «اقْبَلِ الْحَدِيقَةَ وَطَلِّقْهَا تَطْلِيقَةً»، رواه البخاري.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه السنة — السيد سابق (كتاب الطلاق)', 1);
  END IF;

  -- 5) الحضانة والنسب
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='1fa39f54-501f-4030-9f96-90e63b6593ee' AND title='أحقية الأم بحضانة ولدها ما لم تتزوج') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أحقية الأم بحضانة ولدها ما لم تتزوج', 'معنى الحضانة وأحق الناس بها بعد الفراق، وأهمية حفظ نسب الولد وإلحاقه بأبيه', '1fa39f54-501f-4030-9f96-90e63b6593ee', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وأحق الناس بها', 'الحضانة: القيام بتربية الصغير ورعايته ومصالحه فيما لا يستقل به. والأم أحق الناس بحضانة ولدها عند جمهور الفقهاء لشفقتها وقدرتها على رعايته، وتسقط حضانتها عند أكثرهم إذا تزوجت بأجنبي عن الصغير، مراعاة لمصلحته. والنسب هو الصلة الشرعية بين الولد وأبيه، ويجب إلحاق الولد بأبيه وعدم نسبته لغيره.', 1),
    (v_lesson, 'evidence', 'أصل الأمر بالنسب وأحقية الأم بالحضانة', 'قال تعالى: ﴿ادْعُوهُمْ لِآبَائِهِمْ هُوَ أَقْسَطُ عِندَ اللَّهِ﴾ (الأحزاب: 5)، وعن عبد الله بن عمرو رضي الله عنهما أن امرأة قالت: يا رسول الله، إن ابني هذا كان بطني له وعاءً، وثديي له سقاءً، وحجري له حواءً، وإن أباه طلّقني وأراد أن ينتزعه مني، فقال لها رسول الله صلى الله عليه وسلم: «أَنْتِ أَحَقُّ بِهِ مَا لَمْ تَنْكِحِي»، رواه أبو داود وأحمد، وحسّنه الألباني وشعيب الأرناؤوط.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الأحوال الشخصية — الإمام محمد أبو زهرة (باب الحضانة)', 1);
  END IF;

  -- 6) الرضاع
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='f056604a-d4ad-4e42-be9c-145397d9c45b' AND title='تحريم الرضاع وضابطه الزمني') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تحريم الرضاع وضابطه الزمني', 'أثر الرضاع في تحريم النكاح كأثر النسب، وضابط مدته المعتبرة عند الفقهاء في الحولين', 'f056604a-d4ad-4e42-be9c-145397d9c45b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وأثره', 'الرضاع المحرِّم: وصول لبن المرأة إلى جوف الرضيع في مدة معتبرة شرعاً، وله أثر شرعي عظيم إذ يحرِّم من النكاح كل من يحرم بالنسب، فتصير المرضعة أمّاً للرضيع من الرضاعة وأخواتها خالاته وإخوتها أخواله، بشرط أن يقع الرضاع في الحولين الأولين من عمر الطفل عند جمهور الفقهاء.', 1),
    (v_lesson, 'evidence', 'أصل مدة الرضاع وقاعدة تحريمه', 'قال تعالى: ﴿وَالْوَالِدَاتُ يُرْضِعْنَ أَوْلَادَهُنَّ حَوْلَيْنِ كَامِلَيْنِ لِمَنْ أَرَادَ أَن يُتِمَّ الرَّضَاعَةَ﴾ (البقرة: 233)، وعن عائشة رضي الله عنها أن رسول الله صلى الله عليه وسلم قال: «يَحْرُمُ مِنَ الرَّضَاعَةِ مَا يَحْرُمُ مِنَ الْوِلَادَةِ» متفق عليه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المغني — الإمام موفق الدين ابن قدامة المقدسي (كتاب الرضاع)', 1);
  END IF;

  -- 7) الظهار واللعان
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='cb2aa0b8-4a7c-4fb6-b598-ed5ecbef79bf' AND title='تعريف الظهار واللعان وحكمهما') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف الظهار واللعان وحكمهما', 'معنى الظهار ووجوب الكفارة فيه، ومعنى اللعان وموضعه عند تعذر البينة في قذف الزوج زوجته', 'cb2aa0b8-4a7c-4fb6-b598-ed5ecbef79bf', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما', 'الظهار: أن يشبِّه الرجل زوجته أو جزءاً منها بمن تحرم عليه تحريماً مؤبَّداً كأمه، فيحرم عليه وطؤها حتى يكفِّر كفارة الظهار. واللعان: شهادات مؤكَّدة بالأيمان بين الزوجين، يشهد فيها الزوج أربع شهادات بالله أنه صادق فيما رمى به زوجته من الزنى أو نفي الولد وتشهد هي مثل ذلك على تكذيبه، وهو مخرج شرعي عند تعذر إقامة البينة على القذف.', 1),
    (v_lesson, 'evidence', 'أصل الظهار وقصة أول لعان في الإسلام', 'قال تعالى: ﴿الَّذِينَ يُظَاهِرُونَ مِنكُم مِّن نِّسَائِهِم مَّا هُنَّ أُمَّهَاتِهِمْ إِنْ أُمَّهَاتُهُمْ إِلَّا اللَّائِي وَلَدْنَهُمْ﴾ (المجادلة: 2)، وعن ابن عباس رضي الله عنهما في قصة هلال بن أمية حين قذف امرأته عند النبي صلى الله عليه وسلم فقال له: «الْبَيِّنَةُ وَإِلَّا حَدٌّ فِي ظَهْرِكَ»، فنزلت آيات اللعان فتلاعنا، رواه البخاري.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — الدكتور وهبة الزحيلي (كتاب الظهار واللعان)', 1);
  END IF;

  -- 8) العدة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='b5c3b1a2-565b-41e6-ad13-9b8a69738e32' AND title='تعريف العدة وأقسامها بحسب حال المرأة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف العدة وأقسامها بحسب حال المرأة', 'معنى العدة وحكمتها، واختلاف مدتها بحسب كون المرأة حاملاً أو ذات حيض أو معتدة عن وفاة', 'b5c3b1a2-565b-41e6-ad13-9b8a69738e32', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وحكمتها', 'العدة: مدة تتربص فيها المرأة بعد فراق زوجها بطلاق أو وفاة، امتثالاً لأمر الشرع، تحقيقاً للتثبت من براءة الرحم وإتاحة فرصة للمراجعة في الطلاق الرجعي. وتختلف مدتها بحسب حال المرأة: فذات الحيض تعتد بثلاثة قروء، والحامل بوضع حملها، والمعتدة عن وفاة بأربعة أشهر وعشر إن لم تكن حاملاً.', 1),
    (v_lesson, 'evidence', 'أصل العدة القرآني ومكان اعتداد المرأة', 'قال تعالى: ﴿وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ﴾ (البقرة: 228)، وعن فاطمة بنت قيس رضي الله عنها لما طُلِّقت ثلاثاً وخافت أن يقتحم عليها زوجها منزلها، أمرها النبي صلى الله عليه وسلم قائلاً: «انْتَقِلِي إِلَى بَيْتِ ابْنِ عَمِّكِ عَمْرِو بْنِ أُمِّ مَكْتُومٍ فَاعْتَدِّي عِنْدَهُ»، رواه مسلم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه السنة — السيد سابق (كتاب العدة)', 1);
  END IF;

  -- 9) النفقات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='056fc0cd-b74d-4f09-9714-daf5fc1b4a5a' AND title='وجوب نفقة الزوجة والأولاد وضابطها بالمعروف') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('وجوب نفقة الزوجة والأولاد وضابطها بالمعروف', 'وجوب نفقة الزوج على زوجته وأولاده بقدر سعته، وحكم أخذ الزوجة من مال زوجها الشحيح بالمعروف', '056fc0cd-b74d-4f09-9714-daf5fc1b4a5a', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وضابطها', 'النفقة: ما يجب على الزوج بذله لزوجته وأولاده من طعام وكسوة وسكنى بالمعروف، وهي حق واجب بمجرد عقد الزواج الصحيح والتمكين. وتقدَّر بحسب يسر الزوج وعسره لا بحسب حاجة الزوجة فقط، فعلى الموسر أن يوسِّع وعلى المعسر أن ينفق مما آتاه الله.', 1),
    (v_lesson, 'evidence', 'أصل تقدير النفقة وحكم أخذها بالمعروف', 'قال تعالى: ﴿لِيُنفِقْ ذُو سَعَةٍ مِّن سَعَتِهِ وَمَن قُدِرَ عَلَيْهِ رِزْقُهُ فَلْيُنفِقْ مِمَّا آتَاهُ اللَّهُ﴾ (الطلاق: 7)، وعن عائشة رضي الله عنها أن هند بنت عتبة امرأة أبي سفيان قالت للنبي صلى الله عليه وسلم: إن أبا سفيان رجل شحيح لا يعطيني ما يكفيني ويكفي بَنِيَّ إلا ما أخذت منه وهو لا يعلم، فقال: «خُذِي مَا يَكْفِيكِ وَوَلَدَكِ بِالْمَعْرُوفِ» متفق عليه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — الدكتور وهبة الزحيلي (كتاب النفقات)', 1);
  END IF;

